#include <stdio.h>

// Define transformation functions for each color component
int transform_red(int intensity) {
 return intensity * intensity / 255; // Quadratic mapping for demonstration
}

int transform_green(int intensity) {
 return intensity;
}

int transform_blue(int intensity) {
 return 255 - intensity; // Inverse mapping for demonstration
}

void apply_transformation_functions(int grayscale_image[], int pseudocolor_image[]) {
 for (int i = 0; i < 256; i++) {
 int intensity = grayscale_image[i];
 int red = transform_red(intensity);
 int green = transform_green(intensity);
 int blue = transform_blue(intensity);
 pseudocolor_image[i] = (red << 16) | (green << 8) | blue;
 }
}
